module top_module(

  linear_enc_sign, sign,

  conv_sig
  );input [11:0] linear_enc_sign;
  input sign; 
  output [11:0] conv_sig;


  reg [11:0] negated_temp_conv;

  always @ (*) begin
	 negated_temp_conv = conv_sig;

	 if(sign == 1) begin


	   if(linear_enc_sign == -12'b100000000000) begin
			negated_temp_conv = 12'b011111111111;
      end
		else begin
      negated_temp_conv = (~linear_enc_sign) + 1;
		end

    end
    else begin
       negated_temp_conv = linear_enc_sign;
     end
   end

	assign conv_sig = negated_temp_conv;

endmodule
